import type { HTMLAttributes } from 'react';
import type { SlideProps } from './Slides/Slide/Slide.types';
export interface PopoverOnboardingProps extends Omit<HTMLAttributes<HTMLDivElement>, 'content'> {
    /**
     * Состояние отображения: отображено / скрыто.
     */
    open: boolean;
    /**
     * Обработчик события клика по кнопке закрытия (крестик).
     */
    onClose?: () => void;
    /**
     * Объект или массив объектов, отображаемых в виде слайдов.
     *
     * @property {string} id - Идентификатор слайда.
     * @property {string} title - Заголовок.
     * @property {string} body - Основное содержимое.
     * @property {TActions} actions  - Массив объектов, содержащих параметрами кнопок.
     */
    content: SlideProps | SlideProps[];
    /**
     * Индекс активного слайда, по умолчанию первый.
     */
    activeSlideIndex?: number;
    /**
     * Обработчик события клика по степперу (точки) для смены слайда.
     */
    onPaginationChange?: (index: number) => void;
    /**
     * Пользовательский класс
     */
    className?: string;
}
